    function exploreIsland(row: number, column: number): void {
        // Boundary checks to ensure we don't go out of bounds
        if (row < 0 || row >= numberOfRows || column < 0 || column >= numberOfColumns || grid[row][column] === '0' || grid[row][column] === 'visited') {
            return;
        }
        // Mark the current land cell as visited to avoid recounting
        grid[row][column] = 'visited';
        // Explore adjacent cells (up, down, left, right)
        exploreIsland(row + 1, column);
        exploreIsland(row - 1, column);
        exploreIsland(row, column + 1);
        exploreIsland(row, column - 1);
    }
    // Iterate over every spot on the map
    for (let rowIndex = 0; rowIndex < numberOfRows; rowIndex++) {
        for (let columnIndex = 0; columnIndex < numberOfColumns; columnIndex++) {
