func numIslands(grid: [[Character]]) -> Int {
    var mutableGrid = grid
    var islandCount = 0
    let numberOfRows = mutableGrid.count
    guard numberOfRows > 0 else { return 0 }
    let numberOfColumns = mutableGrid[0].count
    guard numberOfColumns > 0 else { return 0 }
    func sinkConnectedLand(row: Int, column: Int) {
        // Base cases to stop recursion: out of bounds or already water
        if row < 0 || row >= numberOfRows || column < 0 || column >= numberOfColumns || mutableGrid[row][column] == "0" {
            return
        }
        // Mark the current land as visited by sinking it
        mutableGrid[row][column] = "0"
        // Recursively sink all adjacent land pieces
        sinkConnectedLand(row: row + 1, column: column)
        sinkConnectedLand(row: row - 1, column: column)
        sinkConnectedLand(row: row, column: column + 1)
        sinkConnectedLand(row: row, column: column - 1)
    }
    // Iterate through each cell of the grid
    for currentRowIndex in 0..<numberOfRows {
        for currentColumnIndex in 0..<numberOfColumns {
            // If land is found, it signifies a new island
            if mutableGrid[currentRowIndex][currentColumnIndex] == "1" {
                islandCount += 1
                // Sink the entire island to avoid recounting
                sinkConnectedLand(row: currentRowIndex, column: currentColumnIndex)
            }
        }
    }
    return islandCount
}
